// api/mascot.js
// Mascot image embedded as base64 — no file system dependency
const MASCOT_B64 = "";

export default function handler(req, res) {
  const buf = Buffer.from(MASCOT_B64, 'base64');
  res.setHeader('Content-Type', 'image/png');
  res.setHeader('Cache-Control', 'public, max-age=31536000');
  res.send(buf);
}
